const summary = $input.first().json[0] || {};
const paid = parseInt(summary.total_paid || 0);

// Alert thresholds from blueprint
const GATE_0A = 25;   // Gate 0A: place supplement MOQ order
const TRT_DAY1_READINESS_TARGET = 40; // TRT day-1 readiness target: internal commercial-readiness milestone (NOT a regulatory gate)

const alerts = [];
if (paid === GATE_0A) alerts.push(`GATE 0A HIT: ${paid} founding member deposits. Place supplement MOQ order.`);
if (paid === TRT_DAY1_READINESS_TARGET) alerts.push(`TRT DAY-1 READINESS TARGET HIT: ${paid} deposits. Internal commercial-readiness milestone reached.`);

// Also send a daily summary when approaching gates
const summary_line = `Deposits: ${paid} paid (${summary.total_pending || 0} pending, ${summary.total_refunded || 0} refunded)`;

return [{ json: { paid, alerts, summary: summary_line, shouldAlert: alerts.length > 0 } }];
